async function fetchPolymarketOdds() {
  try {
    const response = await fetch('https://gamma-api.polymarket.com/events?limit=5');
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    const data = await response.json();

    if (data && data.events && Array.isArray(data.events)) {
      data.events.forEach((event: any) => {
        const title = event.title;
        let topOutcomeProbability = 0;

        if (event.outcomes && Array.isArray(event.outcomes) && event.outcomes.length > 0) {
          const topOutcome = event.outcomes.reduce((prev: any, current: any) => 
            (prev.probability > current.probability) ? prev : current
          );
          topOutcomeProbability = topOutcome.probability * 100; // Convert to percentage
        }

        const message = `${title}: ${topOutcomeProbability.toFixed(2)}% chance. #Polymarket #Odds`;

        // Ensure the message is under 280 characters
        if (message.length > 280) {
            console.log(message.substring(0, 277) + '...');
        } else {
            console.log(message);
        }
      });
    } else {
      console.log('No events found or unexpected data format.');
    }
  } catch (error) {
    console.error('Error fetching Polymarket data:', error);
  }
}

fetchPolymarketOdds();
